<div class="panel"><h2>Leads e reservas</h2><div class="table-wrap"><table><thead><tr><th>Data</th><th>Cliente</th><th>Telefone</th><th>Aparelho</th><th>Serviço</th><th>Período</th><th>Defeito</th></tr></thead><tbody><?php foreach ($rows as $row): ?><tr><td><?= htmlspecialchars($row['created_at']) ?></td><td><?= htmlspecialchars($row['customer_name']) ?></td><td><?= htmlspecialchars($row['customer_phone']) ?></td><td><?= htmlspecialchars(trim(($row['device_brand'] ?? '') . ' ' . ($row['device_model'] ?? ''))) ?></td><td><?= htmlspecialchars($row['service_type']) ?></td><td><?= htmlspecialchars(trim(($row['desired_date'] ?? '') . ' ' . ($row['desired_period'] ?? ''))) ?></td><td><?= htmlspecialchars($row['issue_description']) ?></td></tr><?php endforeach; ?><?php if (!$rows): ?><tr><td colspan="7">Nenhuma reserva registrada.</td></tr><?php endif; ?></tbody></table></div></div>
